/**
 * Per-chunk fano cache benchmark — repeated-prefix prefill (the hot path).
 *
 * `station.forward(residual, startPos, seqLen)` is a PURE function, so a repeated
 * prefix should replay at geodesicLength:0 — skipping the (often bound-service)
 * forward entirely. This measures forwards / cache hits / TOKEN BURN / wall-clock
 * across a COLD run (all forwards, all burn) and a WARM run (all teleport, zero
 * forwards, zero burn). The stub forward sleeps `FWD_MS` to model the bound-service
 * round-trip the cache eliminates — the win is biggest exactly there.
 *
 * Run: pnpm run gnode -- run open-source/gnosis/distributed-inference-host/src/density-chunk-cache-bench.ts
 */

import { Pipeline } from './pipeline.js';
import type { IStation } from './types.js';

const HIDDEN_DIM = 256;
const VOCAB = 64;
const FWD_MS = 4; // simulated bound-service forward latency (what the cache skips)

function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

function stub(startLayer: number, endLayer: number, role: 'entry' | 'exit', counter: { forwards: number }): IStation {
  return {
    startLayer,
    endLayer,
    role,
    async embed({ tokens }: { tokens: Uint32Array; startPos: number }) {
      const out = new Float32Array(tokens.length * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) {
        out[i] = ((tokens[i % tokens.length] ?? 0) + 1) * 0.001 + (i % 7) * 0.0001;
      }
      return out;
    },
    async forward({ residual, sequenceLength }: { residual: Float32Array; startPos: number; sequenceLength: number }) {
      counter.forwards++;
      await sleep(FWD_MS); // the bound-service round-trip the fano cache replaces
      const out = new Float32Array(sequenceLength * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) out[i] = (residual[i] ?? 0) + 0.01;
      return { residual: out };
    },
    async lmHead() {
      const out = new Float32Array(VOCAB);
      out[3] = 1;
      return out;
    },
  } as unknown as IStation;
}

async function runPrefill(
  pipe: Pipeline,
  promptTokens: Uint32Array,
  counter: { forwards: number },
): Promise<{ ms: number; forwards: number }> {
  counter.forwards = 0;
  const t0 = Number(process.hrtime.bigint());
  await (pipe as unknown as { pipelinedPrefill: (a: { promptTokens: Uint32Array }) => Promise<unknown> }).pipelinedPrefill({ promptTokens });
  return { ms: (Number(process.hrtime.bigint()) - t0) / 1e6, forwards: counter.forwards };
}

async function main(): Promise<void> {
  const counter = { forwards: 0 };
  const stations = [stub(0, 8, 'entry', counter), stub(8, 16, 'exit', counter)];
  const pipe = new Pipeline({ stations, hiddenDim: HIDDEN_DIM, vocabSize: VOCAB });
  const promptTokens = new Uint32Array(64).map((_, i) => (i % 50) + 1); // a shared prefix

  console.log('PER-CHUNK FANO CACHE — repeated-prefix prefill (hot path, bound-service forward)');
  console.log(`  HIDDEN_DIM=${HIDDEN_DIM}  tokens=${promptTokens.length}  sim forward latency=${FWD_MS}ms/call\n`);

  const r1 = await runPrefill(pipe, promptTokens, counter);
  const s1 = (pipe as unknown as { chunkCacheStats(): { hits: number; misses: number; tokenBurn: number; size: number } }).chunkCacheStats();
  const r2 = await runPrefill(pipe, promptTokens, counter);
  const s2 = (pipe as unknown as { chunkCacheStats(): { hits: number; misses: number; tokenBurn: number; size: number } }).chunkCacheStats();

  console.log(`  run 1 (COLD):  ${r1.ms.toFixed(1).padStart(7)} ms   forwards=${String(r1.forwards).padStart(2)}   burn=${s1.tokenBurn}   (misses=${s1.misses}, size=${s1.size})`);
  console.log(`  run 2 (WARM):  ${r2.ms.toFixed(1).padStart(7)} ms   forwards=${String(r2.forwards).padStart(2)}   burn+${s2.tokenBurn - s1.tokenBurn}   (hits=${s2.hits - s1.hits})`);
  const speedup = r1.ms / Math.max(r2.ms, 0.001);
  console.log(
    `\n  → WARM teleports the whole prefill: forwards ${r1.forwards} → ${r2.forwards}, ` +
      `token burn ${s1.tokenBurn} → +${s2.tokenBurn - s1.tokenBurn} (free), ` +
      `${speedup.toFixed(1)}× faster wall-clock. The bigger the bound-service forward, the bigger the win.`,
  );
}

void main();
